INSERT INTO `condensate_disease` VALUES (1, 217, 1, 'NPM1c relocalizes from the nucleolus to the cytoplasm. Return of NPMc to the nucleus via gene editing induces cell growth arrest and differentiation in AML cultured cell lines OCI-AML3 and IMS-M2 and in primary AML cells. Targeted degradation of NPM1c, or treatment with the XPO1 inhibitor KPT-330/selinexor downreagulate HOX/Meis1 gene expression, induce cell growth and differentiation in AML cultured cells lines OCI-AML3 anf IMS-S2. Treatment of NPM1c/FLT3-IDT leukemic mice with KPT-330/selinexor prolonged animal survival, reduced leukemic liver infiltration, spleen wieghts and white blood cell counts.', 'P06748', '30205049');
INSERT INTO `condensate_disease` VALUES (2, 217, 1, 'Growth competition assays in AML cell lines reveal that FBL knockdown resulted in increased cell cycle arrest (G0/G1 phase arrest), myeloid differentiation (CD11b+) and cell death, while flow cytometry show diminished leukaemia stem and progenitor cells (LSPCs; LinŌĆÜ├Ā├ŁCD34+CD38ŌĆÜ├Ā├Ł) and leukaemia stem cells (LSCs; LinŌĆÜ├Ā├ŁCD34+CD38ŌĆÜ├Ā├ŁCD99+Tim3+) after FBL depletion. Furthermore, primary AML patient cells confirm growth defects, myeloid differentiation, increased apoptosis and diminished colony formation upon FBL silencing. In immunodeficient non-obese diabetic (NOD)/severe combined immunodeficiency (SCID) mice transplanted with AML cells, knockdown of FBL led to slower leukaemia progression and extended survival, few leukaemic blast cells in the bone marrow, spleen, and liver, and a significant reduction in leukaemia cell frequencies in peripheral blood, bone marrow, and spleen. In HL-60 cells, deletion of the intrinsically disordered GAR domain and a chimeric FBL mutant, H2B-MD, with the GAR domain substituted with a non-IDR sequence from H2B failed to recover AML characteristics. Full restoration was observed using the MD-GAR mutant containing GAR and MD in revised order and the chimeric RGG-MD mutant with the FBL IDR replaced with a similar glycine- and arginine-rich sequence from NOLA1. Live-cell imaging of AML cells show GAR-defective mutants (MD, H2B-MD and PLD-MD) generated smaller puncta, failing to fully separate from fibrillar centre proteins and forming an incomplete hollow structure while RBD-defective mutants (GAR and GAR-Helix) exhibited fewer and larger condensates that dispersed across the nucleus yet still excluded fibrillar centre proteins. FRAP revealed GAR-defective mutants displayed higher mobility, as evidenced by faster fluorescence recovery after bleaching, and RBD-defective mutants (GAR and GAR-Helix) exhibited limited dynamics.', 'P22087,P06748', '38745030');
INSERT INTO `condensate_disease` VALUES (3, 257, 1, 'Elevated levels of P-bodies that sequester mRNA encoding for tumor suppressors promote leukemia progression in vivo in AML mouse models.', 'Q6P2E9,P26196', '39169219');
INSERT INTO `condensate_disease` VALUES (4, 340, 2, 'A╬▓42 causes SG formation in a cell type-specific manner and depends on eIF2╬▒ phosphorylation. Exposure to 20 ╬╝M A╬▓42 led to significant SG formation in neuroblastoma-derived (SH-SY5Y) and glioma-derived (U87) cell lines, but not non-neuronal cell lines. Also, familial mutants Dutch E22Q and Flemish A21G display distinct SG-inducing characteristics. Monomeric and oligomeric forms of A╬▓42 exhibit a 4ŌĆō5 times stronger ability to induce SG formation compared to fibrillar forms. eIF2╬▒ kinases knockout (KO) cell lines show that A╬▓-induced SG formation is dependent on Protein Kinase R (PKR). Proximity ligation assay (PLA) analysis show a close proximity of PACT and PKR in both A╬▓-treated SH-SY5Y and U87 cells, and in Alzheimer\'s Disease (AD) mouse hippocampus indicating A╬▓42 exposure facilitates PACT-PKR interaction.', 'P55884,Q13283', '39966464');
INSERT INTO `condensate_disease` VALUES (5, 340, 2, '5XFAD AD mouse models subjected to anesthesia and surgery exhibit stress granule induction and localization of SYK and phosphorylated SYK within stress granules.', 'P43405,Q13283', '34512311');
INSERT INTO `condensate_disease` VALUES (6, 745, 2, 'BRCA1 aberrantly localizes into tau cytoplasmic aggregates in Alzheimer\'s disease (AD), Pick\'s disease (PiD), and progressive supranuclear palsy (PSP) patient brains.', 'P10636', '31861888');
INSERT INTO `condensate_disease` VALUES (7, 745, 3, 'BRCA1 aberrantly localizes into tau cytoplasmic aggregates in Alzheimer\'s disease (AD), Pick\'s disease (PiD), and progressive supranuclear palsy (PSP) patient brains.', 'P10636', '31861888');
INSERT INTO `condensate_disease` VALUES (8, 745, 4, 'BRCA1 aberrantly localizes into tau cytoplasmic aggregates in Alzheimer\'s disease (AD), Pick\'s disease (PiD), and progressive supranuclear palsy (PSP) patient brains.', 'P10636', '31861888');
INSERT INTO `condensate_disease` VALUES (9, 340, 5, 'Upon treatment with sodium arsenite, immunocytochemistry for PABP in iPSC-derived hMNs from ATXN2-patients show stress granule (SG) defects. ATXN2-ALShMNs cells contain larger stress granules during the recovery phase. Additionally, immunohistochemistry for TUJ1 and CHAT on E13 DIV7 primary motor neuron cultures from ATXN2-Q33 TDP-43Tg-ALS mice show altered SG dynamics.', 'P11940', '39209824');
INSERT INTO `condensate_disease` VALUES (10, 340, 5, 'In hFUS transgenic mice, the spinal cord at the end stage of the disease (39ŌĆō41 days) is marked by a significant increase in the expression of hnRNP A2/B1 isoforms lacking exon 9 (A2b and B1b), downregulation of exon 9-containing isoforms (A2 and B1), and skipping of hnRNP A2/B1 exon 9 (31ŌĆō36 days) occurs concomitantly with the appearance of disease symptoms. Immunofluorescence analysis on mouse primary cortical neurons shows Exon 9 skipping causes redistribution of hnRNP A2/B1 from the nucleus to the cytoplasm, and Exon 9 skipping increases hnRNP A2/B1 recruitment to SGs.', 'P22626,P31483', '40157939');
INSERT INTO `condensate_disease` VALUES (11, 340, 6, 'Cytoplasmic TDP-43 inclusions co-localize with stress granules markers in cellular models and ALS and FTLD-U patient brain tissue. Cytoplasmic inclusions of TDP-43 disease associated mutations correlate with increase in insoluble protein aggregates and cellular toxicity.', 'Q13148', '20948999');
INSERT INTO `condensate_disease` VALUES (12, 340, 5, 'Cytoplasmic TDP-43 inclusions co-localize with stress granules markers in cellular models and ALS and FTLD-U patient brain tissue. Cytoplasmic inclusions of TDP-43 disease associated mutations correlate with increase in insoluble protein aggregates and cellular toxicity.', 'Q13148', '20948999');
INSERT INTO `condensate_disease` VALUES (13, 340, 6, 'DHX30 is recruited into FUS cytoplasmic puncta in ALS patient spinal motor neurons, causing mitochrondrial dysfunction and cytotoxicity', 'P35637,Q7L2E3', '36163369');
INSERT INTO `condensate_disease` VALUES (14, 340, 5, 'DHX30 is recruited into FUS cytoplasmic puncta in ALS patient spinal motor neurons, causing mitochrondrial dysfunction and cytotoxicity', 'P35637,Q7L2E3', '36163369');
INSERT INTO `condensate_disease` VALUES (15, 340, 7, 'Traumatic brain injury (TBI) in Drosphilla induces formation of stress granules (SGs) that co-localize with phosphorylated Ref(2)P and transiently recruit TBPH. Traumatic injury in Drosophila models of ALS (expressing FUS mutants or C9ORF72 repeat expansions) increase levels of Ref(2)P (p62 homologue), enhance animal mortality and locomotive dysfunction.', 'P35637', '29432563');
INSERT INTO `condensate_disease` VALUES (16, 340, 5, 'Traumatic brain injury (TBI) in Drosphilla induces formation of stress granules (SGs) that co-localize with phosphorylated Ref(2)P and transiently recruit TBPH. Traumatic injury in Drosophila models of ALS (expressing FUS mutants or C9ORF72 repeat expansions) increase levels of Ref(2)P (p62 homologue), enhance animal mortality and locomotive dysfunction.', 'P35637', '29432563');
INSERT INTO `condensate_disease` VALUES (17, 340, 5, 'Immunocytochemistry shows that stress granule (SG) component G3BP1 exhibits enhanced interaction with Nup107 in motor neurons derived from patient iPSCs carrying C9orf72 Amyotrophic lateral sclerosis (ALS) mutations, where C9-1 and C9-2 mutant lines exhibited an increased number of SGs and slower SG disassembly following arsenite treatment compared to controls. Co-immunoprecipitation of G3BP1 in iPSC-derived motor neurons (iMNs) revealed increased interactions of G3BP1 with 40 SG components. Neurodegeneration-relevant proteins HSPH1, UBA1, SEP9, and DDX6 were among detected proteins, and immunostaining experiments confirm DDX6 foci colocalize with G3BP1 in SGs. Moreover, Nup107 colocalizes with SGs and aggregates in C9-ALS iMNs. Knockdown of npp-5, the C. elegans ortholog of Nup107, alleviates ALS-associated phenotypes in worm models, including dipeptide repeats production via repeat-associated non-AUG translation, progressive motility decline, and reduced lifespan. Knockdown of npp-5 ameliorated the short lifespan phenotype of C9ubi ALS worms, whereas knockdown of a different nucleoporin, npp-10 (Nup98 ortholog), did not extend the lifespan of C9ubi ALS worms.', 'P26196,P31483,Q13283', '40891053');
INSERT INTO `condensate_disease` VALUES (18, 340, 6, 'Patient-derived fibroblasts expressing mutant TDP-43 or C9ORF72 repeat expansion formed more stress granules (SGs) compared to healthy controls upon exposure to sub-lethal levels of oxidative stress. Under chronic oxidative stress conditions, SG form at a lower level in disease versus healthy fibroblasts. TDP-43 co-localizes with SG only under chronic, but not acute stress conditions. Cells under chronic stress form phospho-TDP-43 fibrils and impair the autophagy pathway.', 'Q01085,Q13148', '32827688');
INSERT INTO `condensate_disease` VALUES (19, 340, 5, 'Patient-derived fibroblasts expressing mutant TDP-43 or C9ORF72 repeat expansion formed more stress granules (SGs) compared to healthy controls upon exposure to sub-lethal levels of oxidative stress. Under chronic oxidative stress conditions, SG form at a lower level in disease versus healthy fibroblasts. TDP-43 co-localizes with SG only under chronic, but not acute stress conditions. Cells under chronic stress form phospho-TDP-43 fibrils and impair the autophagy pathway.', 'Q01085,Q13148', '32827688');
INSERT INTO `condensate_disease` VALUES (20, 340, 6, 'In a sporadic type B frontotemporal dementia (FTD) patient, mildly affected neurons retained nuclear TDP-43 but exhibited small cytoplasmic puncta displaying phosphorylated TDP-43 and intra-condensate demixing within stress granules. Severely affected neurons lost nuclear TDP-43 and displayed large cytoplasmic phosphorylated aggregates interacting with stress granules and showing demixing. In cells showing arsenite-induced demixing, FRAP reveals that TDP-43 dynamics gradually slowed while remaining dynamic under puromycin, indicating TDP-43 hardening during demixing. These demixed puncta were co-stained with HSPB1 and exhibited ubiquitination, linking demixing to TDP-43 aggregation in iPS-motor neurons. In rNLS8 mice, TDP-43 aggregation was absent without hTDP-43╬öNLS induction or in unaffected neurons with induction, and showed either strong colocalization of TDP-43 with stress granules or a distinct demixing pattern. In control postmortem brain samples TDP-43 was predominantly nuclear with no phosphorylated aggregates.', 'Q13148,Q13283', '40412392');
INSERT INTO `condensate_disease` VALUES (21, 340, 5, 'In a sporadic type B frontotemporal dementia (FTD) patient, mildly affected neurons retained nuclear TDP-43 but exhibited small cytoplasmic puncta displaying phosphorylated TDP-43 and intra-condensate demixing within stress granules. Severely affected neurons lost nuclear TDP-43 and displayed large cytoplasmic phosphorylated aggregates interacting with stress granules and showing demixing. In cells showing arsenite-induced demixing, FRAP reveals that TDP-43 dynamics gradually slowed while remaining dynamic under puromycin, indicating TDP-43 hardening during demixing. These demixed puncta were co-stained with HSPB1 and exhibited ubiquitination, linking demixing to TDP-43 aggregation in iPS-motor neurons. In rNLS8 mice, TDP-43 aggregation was absent without hTDP-43╬öNLS induction or in unaffected neurons with induction, and showed either strong colocalization of TDP-43 with stress granules or a distinct demixing pattern. In control postmortem brain samples TDP-43 was predominantly nuclear with no phosphorylated aggregates.', 'Q13148,Q13283', '40412392');
INSERT INTO `condensate_disease` VALUES (22, 340, 6, 'Inhibition of stress granule formation exacerbates disease phenotypes in Drosophila models of neurodegeneration and in cultured primary neurons.', 'Q13283', '39106168');
INSERT INTO `condensate_disease` VALUES (23, 340, 5, 'Inhibition of stress granule formation exacerbates disease phenotypes in Drosophila models of neurodegeneration and in cultured primary neurons.', 'Q13283', '39106168');
INSERT INTO `condensate_disease` VALUES (24, 340, 8, 'Inhibition of stress granule formation exacerbates disease phenotypes in Drosophila models of neurodegeneration and in cultured primary neurons.', 'Q13283', '39106168');
INSERT INTO `condensate_disease` VALUES (25, 340, 5, 'Acute sublethal sodium arsenite treatment (ARS), as a positive control of oxidative stress, induced TDP-43 mislocalization from the nucleus to the cytoplasm, and cytoplasmic stress granule (SG) formation in human neuroblastoma SK-N-BE cells visualized via confocal microscopy. Semi-quantitative RT-PCR show loss of splicing activity upon chronic ARS treatment in human neuroblastoma cells, which induced features of TDP-43 loss and gain of function associated with TDP-43 proteinopathy. Rapamycin was able to significantly diminish formation of cytoplasmic phosphorylated TDP-43 SG in ALS patient-derived primary fibroblasts. Rapamycin also significantly decreased the percentage of patient-derived mC9orf72 iPSC-MNs with cytoplasmic phosphorylated TDP-43 aggregates from 34.3 % to 23.8 % and the percentage of SGs-forming cells from 12.7% to 4.2%.', 'Q13148', '39536963');
INSERT INTO `condensate_disease` VALUES (26, 33, 9, 'G135R rare mutation in VRK1 kinase destabilizes the kinase, reduces its half-life and prevents formation of Cajal bodies in HEK-293T cells.', 'P38432', '31527692');
INSERT INTO `condensate_disease` VALUES (27, 33, 10, 'G135R rare mutation in VRK1 kinase destabilizes the kinase, reduces its half-life and prevents formation of Cajal bodies in HEK-293T cells.', 'P38432', '31527692');
INSERT INTO `condensate_disease` VALUES (28, 33, 5, 'G135R rare mutation in VRK1 kinase destabilizes the kinase, reduces its half-life and prevents formation of Cajal bodies in HEK-293T cells.', 'P38432', '31527692');
INSERT INTO `condensate_disease` VALUES (29, 33, 11, 'G135R rare mutation in VRK1 kinase destabilizes the kinase, reduces its half-life and prevents formation of Cajal bodies in HEK-293T cells.', 'P38432', '31527692');
INSERT INTO `condensate_disease` VALUES (30, 763, 12, 'Immunohistochemical staining reveal ovalbumin (OVA)-induced asthma mice models show colocalization of SUMO1 and TFEB. Immunoprecipitation (IP) of endogenous TFEB SUMOylation in BEAS-2B cells treated with OVA show increased levels of SUMO1 and TFEB. TFEB in AEC cells show increased levels of SUMOylated TFEB after OVA stimulation, suggesting SUMOylation of TFEB is related to allergic airway inflammation. In BEAS-2B cells, TFEB-K361R-EGFP (SUMOylation site mutant) formed increased number of puncta than TFEB-WT-EGFP specify cell line.  TFEB-K361R-EGFP also forms increased number of puncta in nuclei after starvation or OVA-stimulation for 6 h, while TFEB-WT-EGFP shows lowered number of puncta formation. Also, nuclear TFEB-K361R forms distinct puncta that colocalize with LAMP1 mRNAs of target genes during the formation of TFEB condensates, suggesting TFEB puncta are involved in transcription.', 'P19484', '39998815');
INSERT INTO `condensate_disease` VALUES (31, 340, 13, 'G3BP2 and TIAR-positive tress granules (hypoxic stress responses) are activated in low grade astrocytoma and glioblastoma (GBM) tissues, and correlate with poor patient ourcomes.', 'Q9UN86,Q01085', '33203845');
INSERT INTO `condensate_disease` VALUES (32, 340, 14, 'G3BP2 and TIAR-positive tress granules (hypoxic stress responses) are activated in low grade astrocytoma and glioblastoma (GBM) tissues, and correlate with poor patient ourcomes.', 'Q9UN86,Q01085', '33203845');
INSERT INTO `condensate_disease` VALUES (33, 340, 15, 'DDX3X missense mutations cause formation of stress granules in primary neural progenitors and neurons. The DDX3X missense granules show differential protein composition and physical properties, with C-terminal missense mutations exhibiting reduced molecular exchange with the cytoplasm. Clinically severe DDX3X missense mutations induce DNA damage in neurons and accumulation of R-loops in the cytoplasm.', 'Q13283,Q7Z417', '39836689');
INSERT INTO `condensate_disease` VALUES (34, 33, 16, 'Compound heterogeneous mutations in VRK1 identified in sibling patients of Distal hereditary motor neuropathies (dHMNs). These mutations cause protein mislocalization from the nucleus to the cytoplasm and altered coilin expression in patients fibroblasts. VRK1 mutations lead to inhibition of Cajal body formation and impaired neurite length and branching in hiPSC-derived motor neurons.', 'P38432', '31090908');
INSERT INTO `condensate_disease` VALUES (35, 257, 17, 'RNA sequencing analysis in U87MG human donor cells reveals that praja2 plays a role in the regulation of the transcriptional landscape in Glioblastoma multiforme (GBM). Proteomic analysis identified the RNA helicase DDX6 as a novel target of praja2 and in situ immunostaining analyis of U87MG cell lines confirm that a portion of praja2 signal partially colocalizes with DDX6 at P-bodies. Co-immunoprecipitation show praja2 co-purified with other components of P-bodies involved in translational repression, mRNA decapping, and RNA degradation. In U87MG and patient derived GBM cells, activation of cAMP stimulated the assembly of P-bodies in wild-type cells, whereas the number of P-bodies was reduced in praja2 KO cells, demonstrating that activation of GPCR-cAMP-PKA-praja2 axis promotes the assembly of P-bodies. Wild-type or praja2KO GBM cells injected into CD1 nude mice shows that tumor volume was markedly reduced in mice injected with praja2 KO cells compared to controls. Immunohistochemistry confirmed a marked reduction of the proliferative marker Ki67 in praja2 KO tumor samples compared to wild-type. Additionally, overexpression of DDX6 all K/R mutant markedly impaired condensation of P-bodies in Fsk-treated U87MG cells, and expression of the DDX6 ubiquitylation mutant strongly accelerated tumor growth in mice compared to wild-type DDX6.', 'P26196,Q9NPI6', '40148504');
INSERT INTO `condensate_disease` VALUES (36, 208, 18, 'ZNF32 H179A, H183A, and H179A, H183A mutations, but not WT, form nuclear speckles (NS) in ZR-75-30, MCF-7, and MDA-MB-231 breast cancer cells. MTT assay, chrystal violet staining, and EdU staining show ZNF32 single-site mutations (H179A, H183A) but not ZNF32 H179A, H183A and WT promote the proliferation of cells. Subcutaneous xenograft tumor model in nude mice show higher tumor volumes and tumor formation rates in H179A and H183A single-site mutations, but not ZNF32 H179A, H183A double mutations or WT group. Transcriptome sequencing data show ZNF32 H179A and H183A differentially upregulate ISY1-RAB43 and UPK3BL1 as well as downregulating SNX22 expressions.', 'P17041', '40046230');
INSERT INTO `condensate_disease` VALUES (37, 340, 18, 'Stress granules formation is accelerated in breast cancer patients with low levels of PTEN expression and is associated with poor progrnosis and antitumor immune response and drug resistance.', 'Q13283', '39080255');
INSERT INTO `condensate_disease` VALUES (38, 340, 19, 'Environmental exposure to toxic heavy metal Cr(VI) induces stress granule formation to promote malignant properties, such as proliferation rate, sphere formation and malignant markers in human bronchial epithelium BEAS-2B cells.', 'Q13283', '39306064');
INSERT INTO `condensate_disease` VALUES (39, 340, 19, 'Immunoflourescence microscopy of U2OS cells show that cells expressing the p53 DBD-depleted mutants have reduced percentages of cells harboring puncta as compared to those expressing p53 WT. Immunoblot analysis of H1299 cells expressing WT or site-specifically lactylated p53 show that the site-specifically lactylated p53 proteins failed to bind p53RE-DNA or condense into discrete nuclear puncta in response to stimuli. To examine the consequences of p53 lactylation, p53-/- HCT116 cells expressing either the empty vector (p53null), wild-type (p53WT), or the K120&K139-lactylated p53 (p53DualLac) were inoculated in mice and monitored for tumor growth. p53Dual-Lac was more tumorigenic than the p53WT, with levels of p53 K120 and K139 lactylation correlated with tumor volume. Additionally, p53-WT, but not the K120E and K139E disease variants, inhibit cellular proliferation, clone formation, and xenograft tumor growth in HCT116 cells.', 'P04637', '38653238');
INSERT INTO `condensate_disease` VALUES (40, 116, 19, 'Cytoplasmic DDX4-positive, germ-like granules are observed in the cytoplasm of several cancer patient tissues, but not in the normal tissue. The aberrant condensates are further detected in xenograft tumors and spheroid models. DDX4 aberrant condensates are associated with transcriptional reprogramming, tumor growth, cancer invasiveness and poor patient survival.', 'Q9NQI0', '38963760');
INSERT INTO `condensate_disease` VALUES (41, 763, 19, 'ZHX2 forms nuclear condensates in MCF7 cells, T47D cells, and tumors from MDA-MB-231 xenograft tumor-bearing mice and breast cancer patients, with the proline-rich ZHX2 IDR mediating hypoxia-induced LLPS. Fluorescence images, co-localization analysis, and immunoblots of lysates of MDA-MB-231 cells show that ZHX2 forms transcriptionally active condensates in hypoxia. Integration of data from ChIP-seq, RNA-seq, and an assay for transposase-accessible chromatin with high-throughput sequencing (ATAC-seq) reveal hypoxia-induced LLPS of ZHX2 activates a cluster of oncogene transcription that is enriched by metastatic genes distinct from the targets of hypoxia-inducible factor (HIF). LLPS-enhanced phosphorylation of ZHX2 at S625 and S628 partitions CTCF into condensates in MDA-MB-231 cells, and non-invasive bioluminescence imaging in mice and ex vivo imaging of lung tissue showed that ZHX2 depletion inhibited breast cancer lung colonization and outgrowth.', '', '40185097');
INSERT INTO `condensate_disease` VALUES (42, 217, 19, 'Nucleoli are enlarged in rapidly proliferating cells, as measured by AgNOR staining, which stains for Ag-binding proteins localized to the nucleolous, primarily NPM1 and nucleolin. The number and histologic pattern of AgNOR staining allows patient stratification into high risk and low risk, across multiple types of cancer.', 'P06748,P19338', '10588059');
INSERT INTO `condensate_disease` VALUES (43, 257, 19, 'P body assembly is inhibited by highly phosphorylated EDC3 in tumor cells to promote tumor growth and invasion.', 'Q9NPI6,Q96F86', '33586867');
INSERT INTO `condensate_disease` VALUES (44, 8, 20, 'Western blot analysis reveals that ALYREF expression was significantly reduced in doxorubicin (DOX)-treated mouse hearts, mouse cardiomyocytes (CMs), and human induced pluripotent stem cell-derived cardiomyocytes (hiPSC-CMs). In cardiac-specific ALYREF knockout mice (ALYREF CKO), echocardiography revealed that ALYREF CKO mice exhibited significant cardiac dysfunction, elevated creatine kinase-MB (CK-MB) and cardiac troponin T (cTnT), and enlarged left ventricular chambers and pathological cardiac hypertrophy. Cardiac-specific overexpression of ALYREF attenuates DOX-induced cardiotoxic injury in mice; following DOX treatment, mice with ALYREF overexpression exhibited improved survival and preserved body weight compared with controls. Echocardiographic analysis demonstrated that cardiac-specific overexpression of ALYREF significantly preserved left ventricular function, lowered serum levels of CK-MB and cTnT, and mitigation of DOX-induced myocardial atrophy and fibrosis compared to controls. Immunostaining in CMs show that following DOX exposure, ALYREF lost punctate nuclear organization and became diffusely distributed throughout the nucleoplasm with no nuclear translocation. Live-cell imaging of CMs transfected with EGFP-ALYREF confirmed that EGFP-ALYREF formed discrete nuclear condensates, with FRAP recovery occurring within 5 minutes of photobleaching. DOX induced DNA damage by binding to D171 and disrupted ALYREF condensates, indicated by increased ╬│H2AX foci, greater comet tail DNA percentage, and higher nuclear fragmentation. DOX treatment of CMs additionally resulted in decreased binding of ALYREF to RBMX, TOP1, and CDC5L, and mutation of the D171 residue disrupted NARC1 complex assembly, resulting in DNA damage and apoptosis.', 'Q86V81', '40899520');
INSERT INTO `condensate_disease` VALUES (45, 340, 8, 'Mutations in CAPRIN1 cause accumulation in cytoplasmic puncta and colocalize with other neurodegenerative disorder protein markers, including ataxia-related proteins and cause reduced neuronal activity in iPSC-derived neurons, and impaired stress granules dynamics', 'Q13283,Q53GS9,Q14444,Q9UJW0,Q9Y2T1', '36136249');
INSERT INTO `condensate_disease` VALUES (46, 257, 21, 'T. cruzi infection induces P body assembly in HT1080 cell line, to supress the host immune response by inhibiting IL-1b production.', 'Q6P2E9,Q9NPI6', '39122157');
INSERT INTO `condensate_disease` VALUES (47, 217, 22, 'polyGly-Arg (GR) and polyPro-Arg (PR) dipeptides, formed through translation of C9ORF72 repeat expansion, localize to nucleolar substructures and impair biophysical properties of NPM1 in vitro, and disrupt nucleolar dynamics and function in HeLa cells. Additionally, GR and PR induce spontaneous assembly of poorly dynamic stress granules and impair translation. GR and PR directly interact with LCD-containing RNA-binding proteins and alter their biophysical properties, disrupting ribosome biogenesis.', 'P06748', '27768896');
INSERT INTO `condensate_disease` VALUES (48, 340, 23, 'E. Coli infection promotes cGLIS3 circularization and assembly of stress granules (SGs), which in turn promotes ICC progression, demonstrated in colony formation assays and in mouse models of lung metastasis. Hepatolithiasis-ICC patients express higher level of cGLIS3 and poorer prognosis. Mechanisticallty, cGLIS3 forms a complex with hnRNPA1 and G3BP1 to promote SG and activate NF-kB signaling pathway.', 'Q13283', '38368261');
INSERT INTO `condensate_disease` VALUES (49, 340, 24, 'E. Coli infection promotes cGLIS3 circularization and assembly of stress granules (SGs), which in turn promotes ICC progression, demonstrated in colony formation assays and in mouse models of lung metastasis. Hepatolithiasis-ICC patients express higher level of cGLIS3 and poorer prognosis. Mechanisticallty, cGLIS3 forms a complex with hnRNPA1 and G3BP1 to promote SG and activate NF-kB signaling pathway.', 'Q13283', '38368261');
INSERT INTO `condensate_disease` VALUES (50, 340, 25, 'BCR-ABL oncoprotein accumulates into cytoplasmic granules in a panel pf Ph-positive cell lines, as detected by immunofluorescence. Expression of BCR-ABL-EGFP causes formation of cytoplasmic granules in HeLa and Cos-1 cells. These cytoplasmic granules exhibit liquid-like behavior, as inferred from granules fusion observed using live imaging. In HeLa cells, BCR-ABL-EGFP and localizes to stress granules in a tyrosine kinase activity-dependent manner. BCR-ABL granule formation is require to promote Ba/F3 cell proliferation.', '', '31735741');
INSERT INTO `condensate_disease` VALUES (51, 340, 26, 'Patient-derived xenograft (PDX) and patient-derived organoid (PDO) models from samples obtained from a surgically resected clear renal cell carcinoma (ccRCC) patient treated with sunitinib examined by Western blot analysis show increased expression of UBAP2L. Additionally, in RCC cell lines 786-O and Caki-1, sunitinib-resistant cell lines exhibited increased UBAP2L protein expression as compared to parenteral cell lines. ccRCC patients with high UNAP2L expression also showed significantly higher resistance to sunitinib as compared with patients with ccRCC with low UBAP2L expression. In RCC cells lines, UBAP2L knockdown resulted in diminished cell viability, decreased maximal inhibitory concentration (IC50) values, and a reduction in both the number and size of colonies in ccRCC cells following sunitinib treatment, whereas overexpression elicited an opposing response. Furthermore, UBAP2L knockdown significantly increased the sensitivity of 786-O-R and Caki-1-R cells to sunitinib and promoted apoptosis, while overexpression decreased apoptosis and contributed to sunitinib resistance. In orthotopic xenograft model mice, sunitinib combined with UBAP2L knockdown impressively mitigated tumor growth compared with the control group, whereas UBAP2L knockdown or sunitinib alone exhibited a partial inhibitory effect. UBAP2L colocalized with stress granule (SG) marker protein G3BP1 following sunitinib treatment, and knockdown of UBAP2L disrupted SG organization--following sunitinib treatment, UBAP2L knockdown cells exhibited significantly lower levels of G3BP1 accumulation in the SG components. Additionally, immunoprecipitation and immunoblot found that S305 is the principal O-GlcNAcylation site of UBAP2L. UBAP2L S305A mutants exhibited reduced cell viability, diminished colony size and number, reduced angiogenic capacity, and disrupted SG formation in ccRCC cells. UBAP2L S305A mutant group showed slower tumor growth, smaller tumor size, and lower tumor weight in mice. Manipulation of O-GlcNAcylation via OSMI-1 treatment in tandem with sunitinib treatment shows inhibited cell growth and disrupted SG formation in ccRCC cells, slower tumor growth and enhanced survival in mouse models, and significant growth inhibition in PDOs.', 'Q14157,Q13283', '41029457');
INSERT INTO `condensate_disease` VALUES (52, 763, 27, 'TFEB formed condensates under nutrition deprivation, and the N terminus CC domain is required for LLPS. Deletion of this domain inhibited TFEB-mediated target gene expression. TFEB condensates co-localize with EP300 and MED1 forming a transcriptional hub. TFEB inhibitors suppress TFEB puncta formation and abolish IF-mediated amelioration of DSS colitis.', 'P19484', '39729151');
INSERT INTO `condensate_disease` VALUES (53, 257, 28, 'YAP expression increases the number of P bodies in cancer cells, in a mechanism dependent on YAP/TEAD transcriptional activity, to promote cell proliferation and migration.', 'P26196,Q9NPI6', '39046443');
INSERT INTO `condensate_disease` VALUES (54, 217, 29, 'Transfected coronavirus nucleoproteins from TGEV and MHV localize to nucleoli and disrupt cell division.', 'P19338', '11533198');
INSERT INTO `condensate_disease` VALUES (55, 340, 29, 'SARS-CoV-2 infection leads to increased expression of HDAC6 in infected VERO, A549 and Calu-3 cell lines, and promoted viral replication. SARS-CoV-2 infection promotes interaction between G3BP1 and HDAC6, and between SARS-CoV-2 N protein and HDAC6, as measured by immunoprecipitation. Interaction of HDAC6 with the N protein stabilizes HDAC6, as a mechanism of increased expression. N protein expression inhibits formation stress granule induction in response to oxidative stress.', 'Q13283', '39135075');
INSERT INTO `condensate_disease` VALUES (56, 340, 29, 'SARS-CoV-2 infection of ACE2 expressing HeLa cells inhibits stress granule (SG) formation in response to oxidative stress, to promote viral replication. SGs are formed in these cells when treated with sodium arsenite, poly(I:C) or SARS-CoV-2 RNA. G3BP1 and PKR are required for SG formation in response to SARS-CoV-2 RNA. Expression of the SARS-CoV-2 nucleocapsid protein is required for SG inhibition, through a mechanism that involves interaction with G3BP1 and PKR. This mechanism of SG  suppression by the viral nucleocapsid is shared between SARS-CoV, SARS-CoV-2 and MERS-CoV viruses.', 'Q13283,P31483', '34035218');
INSERT INTO `condensate_disease` VALUES (57, 340, 30, 'G3BP1 formed cytoplasmic SGs in uninfected arsenite-treated HEK 293T cells, but no SGs were detected in DENV-2-infected cells. DENV-2 dsRNA, DDX17, and G3BP1 were found to co-localize in infected cells, forming perinuclear aggregates. Western blot results confirmed that DDX17 interacts with G3BP1. Furthermore, DENV-2 mRNA levels were significantly increased in the DDX17 and G3BP1 co-transfection group at 24 hours post-infection, and plaque assays of the culture supernatant confirmed that viral titer was higher in the co-transfection group compared to the control.', 'Q13283', '40383034');
INSERT INTO `condensate_disease` VALUES (58, 208, 31, 'Nuclear speckles in dentate gyrus neurons - monitored via SRSF2 immunofluorescence, undergo morphological changes, including size and share distribution, upon neuronal activation in rat models of epileptic seizures. These morphological changes correlate with changes in transcriptional and splicing programming and protein composition within the nuclear speckles.', 'Q01130', '39197592');
INSERT INTO `condensate_disease` VALUES (59, 208, 32, 'Nuclear speckles in dentate gyrus neurons - monitored via SRSF2 immunofluorescence, undergo morphological changes, including size and share distribution, upon neuronal activation in rat models of epileptic seizures. These morphological changes correlate with changes in transcriptional and splicing programming and protein composition within the nuclear speckles.', 'Q01130', '39197592');
INSERT INTO `condensate_disease` VALUES (60, 15, 33, 'Circular RNA circSPECC1 directly interacts with ATG4B, promoting formation of cytoplasmic ATG4B condensates in gastric cancer (GC) cells, to drive ubiquitination and degradation of ATG4B and suppresses autophagy. This mechanism promotes metastasis in GC patient tissues. ATG4B recovers from photobleaching (FRAP) on the seconds timescale in cytoplasmic condensates formed in GC cells.', 'Q9Y4P1', '38433354');
INSERT INTO `condensate_disease` VALUES (61, 242, 33, 'Paraspeckle disintegration induced by WTX nuclear bodies (WTX-NBs) resulted in enhanced chemotherapy sensitivity and favorable prognosis in gastric cancer (GC). Co-immunoprecipitation and super-resolution microscopy reveal that the short isoform of WTX (WTX-S) specifically disrupted paraspeckle stability in human GC cell line AGS. Confocal fluorescence, immuno-electron microscopy (IEM), and bright-field observations show that WTX-S selectively interacted with and sequestered NONO (also as p54nrb) from paraspeckles, and that interactions between WTX-S and NONO induced formation of WTX-NBs. The coiled-coil domain 2 (WTX-CCD2) directly interacted with NONO-CCD to compartmentalize paraspeckle proteins and subsequently disrupt paraspeckle stability. FRAP assays showed NONO-WT mobility within WTX-NBs, with fluorescence recovery post-bleaching indicating shared fluidity with WTX-S condensates; both WTX-S and NONO puncta disassembled within 104s of 2.5% 1,6-HD treatment.  In MGC803, MKN45, and AGS cell lines, flow cytometry cell cycle, colony formation, wound-healing, invasion assay show that the synthetic peptide WTXAP, based on the WTX-NONO interface, mimicked WTX-NB-mediated paraspeckle disintegration and exhibited potent antitumor activity. In orthotopic xenograft tumor mouse models, immunohistochemical and immunofluorescence analysis show that WTXAP peptide exhibited potent antitumor activity in vivo. Additionally, in AGS cells, treatment with KPT-330 significantly increased the extent of WTX-S-mediated paraspeckle disintegration, sensitizing WTX-high GC to chemotherapy. FRAP assays indicated that KPT-330 increased the mobility of WTX-NBs while reducing their fluorescence recovery time after bleaching.', 'P23246,Q5JTC6-2,Q15233', '41115290');
INSERT INTO `condensate_disease` VALUES (62, 340, 34, 'Genetic variants in the nuclear localization signal of RBM20 hinder its nuclear import and formation of promote cytoplasmic pathogenic RNP granules. Reducing the level of RBM20 expression through treatment with antisense oligonucleotides (ASOs) significantly decreased cytoplasmic RNP granules within RBM20S639G cardiomyocytes. In RBM20S639G (serine-to-glycine substitution in the nuclear localization signal of RBM20) mice, ASO treatment reversed cardiac dysfunction and remodeling as shown by improving ejection fraction, decreasing severity of left ventricular chamber dilation, mitigating left ventricular hypertrophic remodeling, and improving ECG parameters.', 'Q5T481', '40242865');
INSERT INTO `condensate_disease` VALUES (63, 340, 34, 'Immunofluorescent staining in paraffin-embedded tissues and isolated single cardiomyocyte show an RBM20 S639G mislocalizes from nucleus to the sarcoplasm, with formation of protein condensates in the sarcoplasm. Differential expression and alternative splicing analyses show that components of stress granules were dysregulated in RBM20S639G mice when compared to WT, and genes associated with translational regulation were also differentially expressed in RBM20S639G mice. In vivo cardiac functional assessments show increased heart to body weight ratios in mutant two-month-old homozygous mice, but not in heterozygous mice.', 'Q5T481', '35041844');
INSERT INTO `condensate_disease` VALUES (64, 340, 34, 'Immunofluorescence staining of RBM20 mutations in H9c2 cells show that unphosphorylatable amino acid substitutes S638A, S640G, and S638/S640G facilitate export of RBM20 to the cytoplasm and assembly of ribonucleoprotein (RNP) granules. Phosphomimetic mutations S638D and S640D did not restore the nuclear localization. The non-phosphorylation site mutation P641L promoted RBM20 relocalization and the assembly of RNP granules. Transcriptome profiling with deep RNA-seq in RBM20 S637A KI male mice show altered gene expression associated with cardiac dysfunction and RNP granule assembly.', 'Q5T481', '35394688');
INSERT INTO `condensate_disease` VALUES (65, 340, 34, 'RNA-binding protein RBM20 undergoes mislocalization from the nucleus to the cytoplasm, where it forms aberrant ribonucleoprotein (RNP) condensates, in gene-edited humanized pigs expressing RBM20 mutant. These condensates resemble stress granules but are persistent and misregulated, disrupting RBM20’┐Įs normal role in nuclear RNA splicing. Gene-edited pigs harboring RBM20 mutations develop clinical and histological features of DCM: widespread splicing defects in cardiac genes, including titin (TTN), impair normal RNA processing, disrupt sarcomere structure and cardiac contractility. The condensatopathy is recapitulated in iPSC-derived cardiomyocytes; the sarcomere structure disruption is observed in DCM patient myocardium. Cytoplasmic condensates formed by mutant RBM20 in tranfected U2OS cells recover within seconds in FRAP experiments and exhibit wetting and beading properties on the nucleus surface.', '', '33188278');
INSERT INTO `condensate_disease` VALUES (66, 340, 35, 'METTL3 expression increases kanamycin-induced SG formation and attentuates apoptosis and ROS generation in kanamycin-treated HEI-OC1 cells. Kanamycin treatment in hair cells and HEI-OC1 cells cause decreases in METTL3 expression, and cells isolated from cochlear explants of P3 C57BL/6 mice also show decreased METTL3 expression. Administration of aminoglycosides to mice induce SG formation and decrease expression of METTL3 in the cochlea.', 'Q13283,P31483', '39193335');
INSERT INTO `condensate_disease` VALUES (67, 774, 36, 'Infected Huh7 cells undergo dramatic morphological changes concomitant with nucleocapsid (NC) assembly, and have viral factory (VF) condensates which grow over time, associating with vimentin. Loosley coiled NCs were curved, indicating flexibility, and upon interaction with viral components, condense to thick-walled rigid cylinders in cytoplasmic VFs and a reduction in condensate fluidity.', '', '39742805');
INSERT INTO `condensate_disease` VALUES (68, 340, 37, 'BGLF2 is an EBV tegument protein expressed during the EBV lytic infection stage. BGLF2 expressed in 293T cells interacts with componnets of the RISC complex. Expression of BGLF2 in HONE-1 and HeLas cells induced stress granule (SG) formation, and co-localization of BGLF2 and RISC subunits within SGs. Expression of BGLF2 inhibits let-7a miRNA function and causes an increase in SUMO proteins.', 'Q13283', '35007297');
INSERT INTO `condensate_disease` VALUES (69, 257, 37, 'BGLF2 is an EBV tegument protein expressed during the EBV lytic infection stage. BGLF2 expressed in 293T cells interacts with componnets of the RISC complex. Expression of BGLF2 in HONE-1 and HeLas cells inhibited assembly of P bodies. Expression of BGLF2 inhibits let-7a miRNA function and causes an increase in SUMO proteins.', 'Q9NPI6', '35007297');
INSERT INTO `condensate_disease` VALUES (70, 340, 38, 'qRT-PCR and RNA fluorescence in situ hybridization (FISH) analysis shows that circG3BP1 was significantly and consistently upregulated in esophageal squamous cell carcinoma (ESCC) patient samples, where elevated expression of hsa_circ_0003967 was significantly associated with tumor location, histological grade, and advanced T and N stages, and predicted worse overall survival (OS) in patients with ESCC. In ESCC cell lines KYSE30 and TE1, CCK-8 and colony formation assays show circG3BP1 promotes ESCC cell proliferation and suppresses senescence under cisplatin-induced stress. Xenograft mouse models further confirm that circG3BP1 knockdown suppressed, while circG3BP1 overexpression promoted tumor growth, with these effects being more pronounced upon cisplatin treatment. RNA pull-down, RNA FISH, and immunofluorescence assays show that circG3BP1 translocation to SGs is mediated by IGF2BPs through m6A modification. Furthermore, circG3BP1 interacts with SG components TIAR and CAPRIN1, and circG3BP1 facilitates nucleate SG aggregation by reinforcing TIAR-CAPRIN1 interaction. Under cisplatin-induced stress, IGF2BPs facilitate the m6A-dependent translocation of circG3BP1 to stress granules (SGs), where it functions as a scaffold to enhance TIAR-CAPRIN1 interactions, thereby promoting SG nucleation. SG formation suppresses the translation of senescence-associated mRNAs, such as p21, delaying chemotherapy-induced cellular senescence and contributing to cisplatin resistance in ESCC cells via sequestration within SGs, thereby functioning as a translational gatekeeper of the p21-mediated senescence axis. Clinically, elevated circG3BP1 expression is associated with cisplatin resistance in patients with ESCC. These findings reveal a previously uncharacterized m6A-dependent mechanism by which circG3BP1 promotes SG-mediated chemoresistance, providing a promising potential biomarker and therapeutic target for ESCC treatment.', 'Q01085,Q14444', '41037404');
INSERT INTO `condensate_disease` VALUES (71, 102, 39, 'Aberrant transcriptional condensates formed by EWS-FLI1 fusion oncogene induces gene activation at GGAA microsatelite-target genes and drive oncogenic transformation in cultured cells. EWS-FLI1 condensates are dynamic, as demonstrated by fluorescence recovery after photobleaching (FRAP), fluorescence correlation spectroscopy (FCS) and live-cell particle tracking (SPT).', '', '29930090');
INSERT INTO `condensate_disease` VALUES (72, 340, 40, 'Arginine-rich dipeptide repeat proteins (R-DPR) binds to N-terminal fragments of FUS to promote phase separation. Kap╬▓2 prevents and reverses the aggregation and LLPS of wild-type FUS in the presence of arginine-rich dipeptide repeats in vitro. NLS-binding deficient Kap╬▓2W460A:W730A is more efficient in preventing poly(GR) recruitment into stress granules, reduces (GR)100 aggregation and counteracts neuronal toxicity of poly(GR) in primary cortical neurons without affecting normal FUS phase separation.', 'Q13283,P35637', '39747573');
INSERT INTO `condensate_disease` VALUES (73, 340, 41, 'In ST cells, SG formation enhances antiviral innate immunity mediated through the retinoic acid-inducible gene I (RIG-I) signaling pathway, thereby inhibiting TGEV replication. TGEV counteracts SG formation by reducing protein levels of G3BP1 to promote its own replication, with NSP1 exhibiting the strongest inhibitory effect on SGs formation.', 'Q13283', '40239441');
INSERT INTO `condensate_disease` VALUES (74, 340, 13, 'Lobeline impairs glioblastoma (GBM) cell survival by impairing SG disassembly after hypoxia in immortalized U251 and primary human U3085 GBM cells. After a hypoxic challenge, lobeline \"locked\" cells in a stressed state, even after re-exposure to normoxia. This is characterized by retained SGs, elevated levels of phosphorylated eIF2┼Æ┬▒ and a sustained reduction in global protein translation. The disruption of the canonical stress response induced by lobeline resulted in increased cell death in both GBM cell lines.', 'Q01085,Q9UN86', '41053069');
INSERT INTO `condensate_disease` VALUES (75, 340, 42, 'Infection of HeLa cells with four different members of the enterovirus (EV) suppressed stress granule (SG) formation and activation of type I IFN-dependent gene transcription. These mechanisms are mediated by the EV 2Apro and require its protease activity.', 'Q9UN86,P31483', '30867299');
INSERT INTO `condensate_disease` VALUES (76, 340, 42, 'FMDV infection of ╬▒vb6 cells leads to inhibition of stress granule formation (SG) under oxidative stress conditions, in a mechanism dependent on the catalytic activity of the viral proteases Lpro and 3Cpro, which cleave G3BP1 and G3BP2.', 'Q9UN86,Q13283,P31483', '30404792');
INSERT INTO `condensate_disease` VALUES (77, 340, 43, 'Western blotting analysis and immunofluorescence staining of tumor and adjacent non-tumor head and neck cancer (HNC) tissue samples show that protein levels of stress granule (SG) markers G3BP1 and PABP were higher in tumor (T) samples than non-tumor (N) samples, with distinct puncta in the cytosol of T samples only. Immunofluorescence microscopy of FaDu cells show that HSP90 inhibitor 17AGG decreased TBK1 activity and the number of cells displaying SGs in cells experiencing proteotoxic stress induced by MG132, but not in the absence of stress stimuli. Additionally, treatment with chemotherapeutic drug cisplatin significantly induced SG formation, while TBK1 knockdown reduced SG-positive cells by approximately 46%. Additionally, FaDu cells transfected with NC, TBK1, ATG5, or G3BP1 siRNAs treated with cisplatin showed cleaved CASP3 levels were higher in siTBK1- and siG3BP1-treated cells compared to siATG5-treated cells. Use of novel TBK1 inhibitor, GSK8612 suppresses xenograft tumor growth in vivo. p-TBK1 expression in tumors was reduced in GSK8612-treated mice compared to control mice, and immunofluorescence of tumor sections revealed that SGs were significantly reduced in GSK8612-treated tumors compared to control tumors.', 'P11940,Q13283', '40114316');
INSERT INTO `condensate_disease` VALUES (78, 242, 44, 'Palmitic acid (PA) and oleic acid (OA) applied to tumor-tissue derived organoids and hepatocellular carcinoma (HCC) cell lines (HepG2, HCCLM3, Huh7, Hep3B) were employed to imitate pathological lipid overload in metabolic dysfunction-associated steatohepatitis (MASH). Organoids reveal m6A-modified circTACC3 is up-regulated in MASH-related HCC. Additionally, circTACC3 functionally facilitates the growth, lipid accumulation, and adaptive survival of organoids and HCC cells under lipid overload condition in a manner depending on its expression and location. circTACC3 interacted directly with NONO/p54nrb to assemble intranuclear paraspeckles. Fluorescence lifetime imaging microscopy-Forster resonance energy transfer (FLIM-FRET) assays further validated a direct interaction between circTACC3 and NONO/p54nrb. This process was dependent on the m6A-modification sites of circTACC3 and facilitated its nuclear retention. DRIP-ChIRP-sequencing demonstrated that circTACC3-containing paraspeckles were recruited to DNA double-strand break (DSB) foci to form R loops (DSB-circTACC3-R loops). DSB-circTACC3-R loops further facilitated the contact and fusion of topologically associated domains (TADs) and selectively activated genes related to the malignant phenotype of MASH-related HCC. circTACC3-R loops exerted positive feedback control over the assembly of circTACC3 paraspeckle and clustering of TADs.', 'Q15233', '41103024');
INSERT INTO `condensate_disease` VALUES (79, 242, 45, 'Palmitic acid (PA) and oleic acid (OA) applied to tumor-tissue derived organoids and hepatocellular carcinoma (HCC) cell lines (HepG2, HCCLM3, Huh7, Hep3B) were employed to imitate pathological lipid overload in metabolic dysfunction-associated steatohepatitis (MASH). Organoids reveal m6A-modified circTACC3 is up-regulated in MASH-related HCC. Additionally, circTACC3 functionally facilitates the growth, lipid accumulation, and adaptive survival of organoids and HCC cells under lipid overload condition in a manner depending on its expression and location. circTACC3 interacted directly with NONO/p54nrb to assemble intranuclear paraspeckles. Fluorescence lifetime imaging microscopy-Forster resonance energy transfer (FLIM-FRET) assays further validated a direct interaction between circTACC3 and NONO/p54nrb. This process was dependent on the m6A-modification sites of circTACC3 and facilitated its nuclear retention. DRIP-ChIRP-sequencing demonstrated that circTACC3-containing paraspeckles were recruited to DNA double-strand break (DSB) foci to form R loops (DSB-circTACC3-R loops). DSB-circTACC3-R loops further facilitated the contact and fusion of topologically associated domains (TADs) and selectively activated genes related to the malignant phenotype of MASH-related HCC. circTACC3-R loops exerted positive feedback control over the assembly of circTACC3 paraspeckle and clustering of TADs.', 'Q15233', '41103024');
INSERT INTO `condensate_disease` VALUES (80, 340, 45, 'Missense mutp53 conferred better overall survival to hepatocellular carcinoma (HCC) patients compared to p53null patients. Knockdown of mutp53 in Huh7 (p53Y220C), SNU449 (p53A161T), and HepG2 (p53wt) HCC cells or overexpressed p53R175H-3XFLAG in p53null Hep3B HCC cells treated with sorafenib (SOR), vincristine (VCR), doxorubicin (DRB), or cisplatin (CDDP) reveal mutp53-expressing Huh7, SNU449, and Hep3B cells showed increased apoptosis compared to p53-knockdown or -null cells following SOR and VCR treatment, but not DRB or CDDP treatment. Additionally, immunofluorescence for CC3 and colony formation assays show mutp53-expressing KHOS/NP cells had more apoptotic cells with reduced colony formation than mutp53-knockdown cells treated with ER-stress inducer, thapsigargin (TG). Overexpression of p53R175H in p53null Hep3B HCC cells and OSC19 head and neck cancer cells resulted in increased apoptosis following TG treatment. Knockdown or knockout of mutp53 significantly increased the number of SG-positive cells following TG treatment in KHOS/NP, PLC/PRF/5 (p53R249S, HCC), and SNU449 cells. Knockdown of mutp53 in SNU449 and Huh7 HCC cells resulted in a consistent and significant increase in eIF2╬▒ phosphorylation (p-eIF2╬▒) and increase in p-PERK following TG treatment. Increased PABP- or eIF4E SG formation due to mutp53 knockdown was reduced by simultaneous G3BP1 knockdown in both SNU449 and KHOS/NP cells following SOR and TG treatment. Hep3B cells expressing FL p53R175H and deletion mutants treated with SOR reveal that the OD domain in mutp53 is required for the mutp53-G3BP1 interaction. Immunocompromised mice bearing control and mutp53-knockdown Huh7 tumors show that mutp53-expressing control tumors responded to SOR, while mutp53-knockdown tumors show reduced sensitivity to SOR. Immunohistochemistry for p53 and CC3, as well as immunofluorescence for PABP and G3BP1 show increased CC3 positivity and a reduced frequency of SG formation in SOR-treated control tumors compared to mutp53-knockdown tumors.', 'P11940,Q13283,P06730', '40064891');
INSERT INTO `condensate_disease` VALUES (81, 33, 46, 'The kinase inactive VRK1-D263G mutant is found in HSP patients with neurologic phenotype and moderate intellectual disability. The mutation causes loss of kinase function in VRK1. When expressed in HeLa cells, the mutant inhibits assembly of Cajal bodies.', 'P38432', '34504951');
INSERT INTO `condensate_disease` VALUES (82, 84, 46, 'The kinase inactive VRK1-D263G mutant is found in HSP patients with neurologic phenotype and moderate intellectual disability. The mutation causes loss of kinase function in VRK1. When expressed in HeLa cells, the mutant inhibits formation of DNA damage response bodies detected via 53BP1 foci.', 'Q12888', '34504951');
INSERT INTO `condensate_disease` VALUES (83, 158, 47, 'LANA bodies are viral episomes, located in the nucleus of the host cell, containing viral genome and the KSHV protein LANA, which form via phase separation. LANA bodies are dynamic structures that change during the cell cycle and viral life cycle. The host protein DAXX localizes to LANA bodies under latent infection, and it is ejected during the transition to lytic replication. LANA bodies form ring-like microscopic structure that associate with KSHV DNA during lytic reactivation.  1,6-hexanediol treatment partially dissolves LANA bodies and alters KSHV genome conformation.', 'P38432', '33471863');
INSERT INTO `condensate_disease` VALUES (84, 231, 48, 'ORC1 is a host factor that associates with the HIV-1 promoter and host repressive epigenetic factors within nuclear condensates to maintain enriched repressive histone modifications (HDAC1, HDAC2) on the HIV-1 promoter, as a mechanism for maintaining HIV-1 latency in J.Lat cells. ORC1 regulates DNA methylation of the HIV-1 promoter, through interactions with DNMT1. ORC1 form nuclear condensates and co-localizes with HP1a, SUV39H1, EZH2, H3K9me3, H3K27me3 in ORC1-GFP transfected HEK293 cells. The ORC1 nuclear condensates recover from photobleaching (FRAP) on the timescale of tens of seconds, and exhibit fusion and fission, demonstrating liquid-like fluidity. GFP-ORC1-IDR forms condensates in vitro in a concentration-dependent fashion; the in vitro condensates dissolve with increase in buffer ionic strength. Depletion of ORC1 reactivated HIV-1 in primary CD4+ T-cells from people living with HIV-1.', '', '39082875');
INSERT INTO `condensate_disease` VALUES (85, 135, 48, 'HIV-1 membraneless organelles (HIV-1-MLOs) persist in macrophage-like cells (THP-1) in the presence of nevirapine, and build during in vivo infection of mice. Immune RNA-FISH and the MCP-MS2 system show that CPSF6 condensates co-exist with active proviruses and shield viral RNA genome. CPSF6 condensate disassembly impedes nuclear viral reverse transcription after nevirapine removal in THP-1 cells. HIV-1 MLOs shield the final reverse transcription product from host immune detection.', '', '39623137');
INSERT INTO `condensate_disease` VALUES (86, 340, 49, 'Stress granules assembly is induced by viral infections in cells containing high but not low levels of copy-back viral genomes.', 'Q01085,Q13283', '37983241');
INSERT INTO `condensate_disease` VALUES (87, 340, 50, 'Stress granules assembly is induced by viral infections in cells containing high but not low levels of copy-back viral genomes.', 'Q01085,Q13283', '37983241');
INSERT INTO `condensate_disease` VALUES (88, 40, 51, 'Baicalein (BA) significantly attenuated liver injury (AST and AST decreasing), inflammation (interleukin-6, interleukin-8 and tumor necrosis factor-alpha decreasing, and collagen deposition in carbon tetrachloride (CCl4)-induced fibrotic mice. In transforming growth factor-┼ÆŌēż1-activated LX-2 human hepatic stellate cells (HSC), BA suppressed cellular activation while inducing senescence through G1-phase cell cycle arrest and glycolysis inhibition (lactate decreasing). BA directly bound to CEBPZ, suppressing its LLPS and subsequently enhancing TP53 transcription. This activation of the p53/HK2 axis drove HSCs senescence and attenuated fibrosis. Pharmacological inhibition of p53 with pifithrin-┼Æ┬▒ hydrobromide abolished BA\'s anti-fibrotic effects. BA\'s anti-fibrotic efficacy was entirely lost in CEBPZ-knockdown models.', 'P52789', '41075517');
INSERT INTO `condensate_disease` VALUES (89, 217, 52, 'USP39 is a deubiquitylating enzyme that undergoes LLPS in the nucleolus through the N-terminal disordered region. USP39 silencing leads to growth and migration inhibition in lung adenocarcinoma A549 and H1299 cell lines. MTT, colony formation and transwell assays show that absence of the USP39 IDR region and the C-terminal domain damages the oncogenic activities of USP39 in lung adenocarcinoma. Transcriptomic analysis revealed that phase-separated USP39 was associated with GLI1 expression. Western blots of lung cancer and adjacent normal tissue pairs show elevated protein levels of USP39 and GLI1. Analysis of the association between patient survival and mRNA levels show high expression of GLI1 were associated with poorer prognosis.  USP39 knockdown suppresses GLI1 expression, and USP39 knockdown effectively hinders xenograft growth in athymic nude mice.', 'USP39', '39885503');
INSERT INTO `condensate_disease` VALUES (90, 763, 52, 'SP1 expression levels are higher in LUAD tissues compared to normal lung tissue. SP1 forms condensates at the superenhancer site that controls RGS20 transcription to promote cell proliferation and metastasis.', 'P08047', '38976739');
INSERT INTO `condensate_disease` VALUES (91, 340, 53, 'A gene knock-down model of G3BP1, a core SG molecule, in mice and HepG2 cells was constructed to explore the role of SGs in metabolic dysfunction-associated fatty liver disease (MAFLD) induced in vivo by a high-fat diet or in cellulo by palmitic acid (PA). G3BP1 and TIA1 expression were upregulated in both PA-induced HepG2 cells and high-fat diet-fed mouse liver tissues, and showed increased colocalization in the livers of obese but not lean mice. G3BP1 deficiency aggravated liver lipid deposition and insulin resistance in obese mice, confirmed via PA-induced hepatocytes. RNA-seq show G3BP1 slowed down MAFLD progression by inhibiting APOC3.', 'Q13283', '40230220');
INSERT INTO `condensate_disease` VALUES (92, 257, 54, 'PSMB8 undergoes alternative splicing to i2R-PSMB8 in MS white matter lesions (WMLs). Quantification of EDC4 indicate induced P-body formation in primary human cortical astrocytes, leading to phosphorylation of UPF1 and thus increased nonsense-mediated decay (NMD). P-body load is increased in postmortem MS lesions within astrocytes, potentially indicating a dysregulation in splicing of many genes within the MS white matter lesions.', 'Q6P2E9', '38812791');
INSERT INTO `condensate_disease` VALUES (93, 340, 55, 'Stress granule levels are reduced in vivo, in a diabetes ischemia-reperfusion rat model, and in a high glucose hypoxia/reoxygenation cell model and correlate with increased myocardial tissue damage, apoptosis and inflammatory factors.', 'Q13283,P31483', '38988216');
INSERT INTO `condensate_disease` VALUES (94, 4, 56, 'Image-based high-throughput screening of MCF-7 cells show that the phosphatidylinositol 3-kinase (PI3K)/AKT signaling axis meditates A-body formation during stress exposure, with AKT activation repressing glycogen synthase kinase-3 (GSK3)-mediated degradation of c-Myc. qPCR showed that inhibitors of PI3K (Pilaralisib, Torin1, Ipatasertib), mTORC1/2, and AKT reduced heat-mediated induction of rIGS16RNA without affecting GAPDH mRNA levels, observed in siRNA-mediated depletion of AKT1 as well. c-Myc accumulates in the nucleolus during heat shock to induce rIGS16RNA expression. In MCF-7  and U-87 MG cells, depletion of c-Myc using siRNA reduced both A-body formation and levels of rIGS16RNA expression under heat shock conditions without affecting GAPDH, suggesting that c-Myc activity is involved in this amyloid aggregation pathway.', '', '40272983');
INSERT INTO `condensate_disease` VALUES (95, 217, 56, 'In MCF-7 cells, c-Myc accumulates in the nucleolus during heat shock to induce rIGS16RNA expression. qPCR shows this occurs prior to the heat-induced expression of rIGS16RNA, highlighting that nucleolar localization is not mediated by rIGSRNA itself.', 'P22087,Q99417', '40272983');
INSERT INTO `condensate_disease` VALUES (96, 277, 57, 'Anti-m1A dot-blot assay show ocular melanoma samples present attenuated m1A levels and increased ALKBH3 protein levels. KaplanŌĆōMeier curves of tumor recurrence reveal poor outcomes with elevated ALKBH3 levels. ALKBH3-deficient ocular melanoma cells (92.1, OMM2.3 and CRMM1) show an increase of m1A levels, and and attenuation of cell growth, colony forming capacity, and decreased migration capacity. Injection of luciferase-labeled control and ALKBH3-silenced 92.1 melanoma cells into nude mice show a weaker signal intensity in ALKBH3-deficient ocular melanoma cells than in control cells. Correlation analysis of the relative protein expression of ALKBH3 and H3K18la level in ocular melanoma cells and normal melanocytes, and CUT&Tag and ChIP-seq of H3K18la analysis reveal histone lactylation enhances ALKBH3 expression. Western blot, RNA-seq, and qPCR reveal decreased RNA expression level of SP100A in ocular melanoma cells, and immunofluorescence of clinical samples show that SP100A was significantly decreased in the ocular melanoma samples. Overexpression of SP100A result in increased PML protein levels and an increase of PML bodies in ocular melanoma cells. Also, ALKBH3-deficient ocular melanoma cells exhibit an elevation in PML bodies.', 'P29590', '38118002');
INSERT INTO `condensate_disease` VALUES (97, 340, 58, 'Corticospinal axons in injured spinal cord contain more G3BP1-TIA1 granules in mice with a rostralized progenitor graft, which does not support regeneration, than those with a caudalized progenitor graft. Immunofluorescence of axons performed at 20 days after spinal cord injury/peripheral nerve graft (PNG) placement showed more axons extending further distances from the spinal cord/PNG apposition in the G3BP1 B-domain-BFP expressing mice compared to the G3BP1-BFP and GFP expressing mice. Additionally, immunofluorescence of retinal ganglion cells (RGCs) from an optic nerve injury mouse model showed that G3BP1 B-domain expression in RGCs greatly increases axon regeneration. G3BP1 B-domain expression in reticulospinal neurons and RGCs resulted in smaller and fewer G3BP1 granules in the axons compared to G3BP1 and control GFP expression, and transduction with AAV2-G3BP1 B-domain-BFP increased postinjury RGC survival compared to controls. Also, injection of a cell-permeable G3BP1 B-domain peptide increases nerve regeneration in mouse mid-thigh sciatic nerve crush injuries. G3BP1 192-205 (EP7) CPP significantly reduces both the density and size of axonal G3BP1 granules in embryonic rat cortical neurons.', 'Q13283,P31483', '40014573');
INSERT INTO `condensate_disease` VALUES (98, 274, 59, 'Plectin (Plec) enhances osteoblast differentiation and bone formation via its intrinsically disordered region (IDR)-mediated phase separation. Plectin promotes osteoblast differentiation by sequestering Anxa2 through phase separation. Furthermore, the functional amino acid region (aa 1967ŌĆÜ├ä├¼2185) of plectin exhibited therapeutic effect in ovariectomized and hindlimb unloading (HLU) mice.', 'P07356,Q9QXS1', '41047030');
INSERT INTO `condensate_disease` VALUES (99, 340, 59, 'Expression of HuR levels and HuR-positive stress granules (SG) positively associate with bone formation, with lower levels observed in older patients. HuR overexpression increased G3BP1 and Colla1 gene and protein expression and promoted SG formation in MC3T3-E1 cells. HuR overexpression increased G3BP1 and Runx2 gene and protein expression, promoted SG formation and induced osteogenic markers in mouse primary osteoblasts. HuR overexpression increased mRNA and protein levels of ╬▓-catenin, recruits ╬▓-catenin into SGs in MEC3T3-E1 cells. to facilitate osteogenesis in aging. Treatment with HuR activator, apigenin, enhances HuR expression, SG induction and recruitment of ╬▓-catenin and promotes osteoblast differentiation in MC3T3-E1 cells. In vivo, in OVX mouse models, treatment with apigenin promoted HuR, G3BP1 mRNA and protein expression, osteogenic gene expression and bone formation.', 'Q13283,Q15717', '38375951');
INSERT INTO `condensate_disease` VALUES (100, 340, 60, 'Site-specific MARylation of RACK1 is required for stress granule assembly, and depletion of TARG1 enhances stress granule assembly by increasing RACK1 MARylation. RACK1 mutant inhibits the formation of G3BP1 foci in OVCAR3 cells, and both knockdown and chemical inhibition of PAPR14 reduces RACK1 MARylation and reduces stress granule assembly, showing PARP14-mediated, site-specific MARylation of RACK1 drives stress granule assembly. Loss of RACK1 MARylation sensitizes OVCAR3 cells and OVCAR3 xenograft tumors grown in immunodeficient mice to stress and inhibits their growth.', 'Q13283', '39760726');
INSERT INTO `condensate_disease` VALUES (101, 340, 61, 'In human pancreatic cancer cell lines MiaPaCa-2, HPAC, Panc-1, and SU.86.86, individual cancer cells within cell populations show a high degree of heterogeneity in SG levels under various stress stimuli. Single cell analysis across cell-cycle phases in MiaPaCa-2 cells using a Fluorescent Ubiquitination-based Cell-cycle Indicator (FUCCI) system reveal that compared to cells marked as G1- and S113 phase, cells marked as G2-phase had ~6x higher levels of SGs, and S-phase showed a ~1.5x increase in SG levels compared to G1-phase cells. Also, SG levels were higher in G2-phase cells, G1 and S-phase cells showing low levels of SGs. Levels of 15d-PGJ2 were ~10-20x higher in G2-phase cells compared to asynchronous cells, and supplementation of asynchronous cells with increasing concentrations of exogenous 15d-PGJ2 enhanced SG levels up to the levels of G2-phase cells (but supplementation of G2-phase cells with the same concentrations of exogenous 15d-PGJ2 had no impact on SG formation capacity). Treatment of MiaPaCa-2 and HPAC cells with L-PGDS specific inhibitor AT-56 reduced SG formation in ~9x in G2-phase and ~3x in asynchronous cells. Additionally, cPLA2 is specifically required for the enhanced SG formation in G2- 266 phase, and knockdown of cPLA2 by doxycycline-inducible shRNA impaired SG formation in pancreatic cancer cells synchronized in G2-phase, but not in asynchronous cells. In pancreatic cancer cell tissue samples from orthotopic mouse models of pancreatic ductal adenocarcinoma, SG levels were ~3x higher in Geminin positive (S/G2) cells than in Geminin negative (G1) cells indicating that SG formation is influenced by cell-cycle state in vivo. KPC-luciferase cells orthotopically implanted in mice treated with oxaliplatin, cPLA2 inhibitor PYR, or both show an increased SG index in tumors that received oxaliplatin treatment alone, correlating with a higher percentage of G2 phase cells and their ability to promote SG formation. PYR inhibited SG formation in Geminin-positive (S/G2) cells, but not Geminin-negative cells.', 'Q13283,Q04637', '40099649');
INSERT INTO `condensate_disease` VALUES (102, 340, 62, 'Immunofluorescence assays of MIA PaC-2 cells show G3BP2 promotes PDAC gemcitabine resistance in a stress granule (SG) dependent manner. TCGA dataset show that G3BP1 and G3BP2 are significantly upregulated in PDAC, with high expression of G3BP2 associated with poor overall survival. mRNA stability assays show SG in G3BP2 knockdown cells under stress have diminished levels of of PDIA3 mRNA. Knockdown of G3BP2 inhibited the proliferation and invasion of PANCŌĆÉ1 and CFPAC-1 cells in vitro and in vivo. DKC1 was identified as a target of G3BP2, and PDIA3 mRNA stability increased through recruitment to stress granules by G3BP2.', 'Q9UN86', '39289547');
INSERT INTO `condensate_disease` VALUES (103, 208, 62, 'Analysis of a large-scale integrated dataset of human PDACs and a panel of 12 human PDAC cell lines, demonstrated that SIRT6 gene expression levels were higher in classical PDAC compared to basal PDAC samples. SIRT6 protein expression ATF4 is stabilized, and protected from degradation, and relocalized to nuclear speckles by binding to SIRT6 in Panc3.27 cell lines overexpressing SIRT6 and ATF4. In PDX models, tumor growth of basal but nor classical tumors was inhibited by treatment with flavopiridol, an ATP-competitive CDK9 inhibitor).', 'Q01130', '37134154');
INSERT INTO `condensate_disease` VALUES (104, 340, 62, 'NUPR1 undergoes LLPS in vitro homotypically and heterotypically, in the presence of RNA.  NUPR1 colocalizes with G3BP1 in arsenate-induced stress granules (SGs), and promotes induction of a larger number of SGs per cell, compared to cells with NUPR1 knock-down. KRAS-G12D mutation induces overexpression of NUPR1 and formation of NUPR1-dependent SGs in pancreatic cancer cells. Inihbition of NUPR1 with ZZW-115 induces cell death in KRAS-G12D-activated cells. ZZW-115 treatment prevents NUPR1-dependent SG induction and inhibits PDAC development in vivo in Pdx1-cre;LSL-Kras-G12D mouse models.', 'Q13283,O60356', '38360999');
INSERT INTO `condensate_disease` VALUES (105, 340, 63, 'Cholesterol enhanced resistance of MMQ cell lines to cabergoline, and in vivo experiments revealed that a high-cholesterol diet for six weeks resulted in elevated levels of cholesterol and triglycerides in nude mice. Immunoprecipitation combined with mass spectrometry show cholesterol increased binding affinity between DRD2 and stress granule (SG) protein G3BP1. Fluorescence staining of SGs using TASG in MMQ cells, immunohistochemical staining of G3BP1 in mice tumor xenografts, and immunohistochemical staining of G3BP1 in sensitive and resistant human prolactinomas show that cholesterol promoted the formation of stress granules. Interfering with the formation of SGs by overexpressing of USP10 and using the small molecule Integrated Stress Response Inhibitor (ISRIB) reversed cholesterol’┐Įs effect on DRD2 cellular distribution and DA resistance in MMQ cells.', 'Q13283', '40281543');
INSERT INTO `condensate_disease` VALUES (106, 179, 64, 'Negri bodies are viral factories containing viral proteins P and N and form in the cytoplasm of cells infected with the Rabies virus (RABV). They exhibit liquid-like properties as evidenced by fusion observed with live imaging, and P protein fluoerescence recovers within seconds in FRAP experiments. Negri bodies are not miscible with stress granules.', 'na', '28680096');
INSERT INTO `condensate_disease` VALUES (107, 340, 64, 'Stress granule (SG) induction by infection of 293T cells with the avirulent Rabies virus strain Ni-CE; the more virulent strains Nishigahara and street RABV, show reduced induction of SGs. Supression of SG induction is dependent on the sequence of the viral RABV matrix protein (RABV-M), primarily at positions 29 and 95. Variability at position 95 in RABV-M leads to phosphorylation of eiF2a in Ni-CE infected cells, but not cells infected with the more virulent strains. Cells infected with virus expressing RABV-M capable of inducing SGs stimulates RIG-I accumulation and initiation of IFN-b transcription.', 'Q01085,Q13283,P31483', '36069552');
INSERT INTO `condensate_disease` VALUES (108, 340, 64, 'Pseudorabies virus (PRV) infection inhibits SG formation in PK15 and H1299 cells. PK-15 cells infected with PRV show PRV infection promotes G3BP1 nuclear translocation in infected host cells. Confocal microscopy and statistical analyses of SG formation showed that expression of IE180 significantly inhibited poly(I:C)- or arsenite-induced SG formation as compared with US1. Co-immunoprecipitation (co-IP) assays report the interaction between PRV IE180 and endogenous G3BP1 in PRV-infected PK-15 cells, and immunofluorescence assays showed that both GFP-G3BP1 and GFP-G3BP2 colocalized with IE180 protein in the nucleus. H1299 G3BP knockout cell lines show that viral gB protein expression levels were substantially increased in PRV-infected H1299 G3BP1ŌłÆ/ŌłÆ cells compared to WT, and the viral titer in PRV-infected H1299 G3BP1ŌłÆ/ŌłÆ cells was significantly higher than WT.', 'Q9UN86,Q13283,P31483', '40145738');
INSERT INTO `condensate_disease` VALUES (109, 340, 65, 'SGs were detected in retinal ganglion cells in rat models, and exhibited heightened SG formation in response to prolonged light exposure.', 'Q13283', '39813056');
INSERT INTO `condensate_disease` VALUES (110, 340, 66, 'African swine fever virus (ASFV) inhibits stress granule formation in Porcine pulmonary alveolar macrophages (PAMs) despite SG induction via Ars. ASFV increases intracellular GSH by upregulating mitochondrial pAIFM1, and inhibition of ferroptosis pathway factors. GSH inhibitor BSO and activator NAC promotes SG formation in mock-infected PAMs.', 'Q13283', '39707514');
INSERT INTO `condensate_disease` VALUES (111, 277, 67, 'Adenovirus capsid protein VI accumulates into PML bodies upon viral entry in infected U2OS cells and displaces Daxx from PML bodies and translocates it into the cytoplasm, to I nhibit Daxx-mediated repression of the immediate early Ad E1A promoter..', 'P29590', '22427750');
INSERT INTO `condensate_disease` VALUES (112, 242, 68, 'Paraspeckle dynamics regulate gluconeogenesis in hepatocytes. Diabetes-relevant proline levels inhibit formation of paraspeckles in hepatocytes via suppression of Neat1 expression by NONO binding, and promotes hepatic gluconeogenesis through paraspeckle mRNA retention axis in mice. Proline selectively regulated paraspeckle mRNA retention of metabolism-related mRNA and expression of PGC1╬▒ and FOXO1 hepatocytes, with Ppargc1a and Foxo1 mRNAs colocalizing with Neat1 in the nucleus. Modulating paraspeckle dynamics ameliorates hyperglycaemia in diabetic mice.', 'Q15233', '39820557');
INSERT INTO `condensate_disease` VALUES (113, 145, 69, 'CHPV proteins nucleocapsid (N), phosphoprotein (P) and large (L) form cytoplasmic inclusion bodies (CHPV-IBs) and recruit host stress granule proteins (TIA-1, PABP1, eIF╬Ę, G3BP1, Ago2) in CHPV infected Vero and N2A cells. CHPV-IB form independently of PKR and eIF2a phosphorylation, but recruit PKR to promote viral replication.', 'P11940,Q13283,P31483,O15372', '39066190');
INSERT INTO `condensate_disease` VALUES (114, 340, 70, 'Zika virus strain GUINEA-18 suppresses stress granule formation in response to osmitoc and oxidative stress, to promote lower viral replication rates, innate immune response and weaker cytotoxicity compared to a strain that does not suppress stress granule formation, in infected A549 cells.', 'Q13283', '38968296');
INSERT INTO `condensate_disease` VALUES (115, 340, 70, 'ZIKV protein NS2B promotes eIF2╬▒ dephosphorylation through a PP1╬▒-dependent mechanism, to inhibit stress granule (SG) formation under oxidative stress, and evade the host antiviral response in infected HeLa cells. The NS2B-mediated mechanism of SG suppression is shared among multiple members of the flavivirus family: Dengue, West Nile, Yellow Fever, Zika and Japanese encephalitis virus.', 'Q13283,P31483', '38935808');
